/**
 * Generates the full set of Tauri desktop icons from the SVG favicon.
 * Tauri requires specific icon sizes and formats:
 *   - 32x32.png, 128x128.png, 128x128@2x.png  (used in bundle config)
 *   - icon.png (1024x1024, used by tauri icon command as base)
 *
 * NOTE: icon.icns (macOS) and icon.ico (Windows) are generated by
 *       `npx tauri icon` from icon.png — this script just makes the PNGs.
 *
 * Run once: node scripts/generate-tauri-icons.js
 */
import sharp from 'sharp';
import { readFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root      = join(__dirname, '..');
const svgPath   = join(root, 'public', 'favicon.svg');
const outDir    = join(root, 'src-tauri', 'icons');

if (!existsSync(outDir)) mkdirSync(outDir, { recursive: true });

const svg = readFileSync(svgPath);
const bg  = { r: 134, g: 59, b: 255, alpha: 1 }; // #863bff

const pngSizes = [
  { name: '32x32.png',       size: 32  },
  { name: '128x128.png',     size: 128 },
  { name: '128x128@2x.png',  size: 256 },
  { name: 'icon.png',        size: 1024 }, // base for tauri icon to generate .icns / .ico
];

for (const { name, size } of pngSizes) {
  const out = join(outDir, name);
  await sharp(svg)
    .resize(size, size, { fit: 'contain', background: bg })
    .png()
    .toFile(out);
  console.log(`✓ src-tauri/icons/${name}`);
}

console.log('\nPNGs done.');
console.log('To generate icon.icns + icon.ico, run:');
console.log('  node node_modules/@tauri-apps/cli/node_modules/.bin/tauri icon src-tauri/icons/icon.png');
console.log('  (or: npx tauri icon src-tauri/icons/icon.png)');
